 82→const attachRepostSources = async (journals) => {
 83→    const items = Array.isArray(journals) ? journals : [journals];
 84→    const sourceIds = [...new Set(
 85→        items
 86→            .filter(j => j.is_repost === true && j.repost_source_journal_id != null)
 87→            .map(j => j.repost_source_journal_id)
 88→    )];
