 90→    if (sourceIds.length === 0) {
 91→        items.forEach(j => { j.repost_source = null; });
 92→        return journals;
 93→    }
 94→
 95→    const { data: sources, error } = await supabase
 96→        .from('journals')
 97→        .select('id, title, content, preview_text, thumbnail_url, post_type, created_at, users(id, name, image_url, badge)')
 98→        .in('id', sourceIds);
 99→
100→    if (error) {
101→        console.error('supabase error fetching repost sources:', error.message);
102→        items.forEach(j => { j.repost_source = null; });
103→        return journals;
104→    }
105→
106→    const sourceMap = new Map(sources.map(s => [s.id, s]));
107→    items.forEach(j => {
108→        j.repost_source = j.repost_source_journal_id
109→            ? (sourceMap.get(j.repost_source_journal_id) || null)
110→            : null;
111→    });
112→
113→    return journals;
114→};
